// // This D-flip-flop sets Q to 1 on reset and holds the last value of D on the rising edge of the clock.
module DFlipFlop (
    input clk,
    input rst,
    input D,
    output reg Q
);
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            Q <= 0;
        end else begin
            Q <= D;
        end
    end
endmodule
